#include <iostream>
using namespace std;
int main(){
    ______________
    return 0;
}

以下程序的输出结果为______。
#include <iostream>
using namespace std;
int main(){
    int a = 3;
    int *b = &a;
    int &c = a;
    c = *b * 2 + 1;
    cout << a;
    return 0;
}

以下程序的输出为______。
#include <iostream>
using namespace std;
int main(){
    int &a = 3;
    int *b = &a;
    int c = a;
    c = *b * 2 + 1;
    cout << a;
    return 0;
}

有代码段如下，则运行结果为______。
#include<iostream>
struct A{ int data; void Init(){data=5;} };
int main(){ A a; a.Init(); std::cout<<a.data; return 0; }

若有
class A { private: int data; friend class B; };
class B { void Func() { A a; a.data = 5; } };
则必然出现编译错误。

若有
class A { private: int data; };
class B { void Func() { A a; a.data = 5; } friend class A; };
则必然会出现编译错误。

